import xml.etree.ElementTree as ET
from xml.sax.saxutils import escape

def parse_xml(file):
    tree = ET.parse(file, ET.XMLParser(remove_empty_space=True, resolve_entities=False))
    root = tree.getroot()

    settings = {}
    for elem in root:
        if len(elem) > 0:
            key = elem.tag
            value = [escape(child.text) for child in elem]
            settings[key] = value

    return settings